currentInstallation.query:
#graphql
  query CurrentAppBillingSafeRead($unknownInstallationId: ID!, $first: Int!) {
    currentAppInstallation {
      id
      launchUrl
      uninstallUrl
      accessScopes {
        handle
        description
      }
      app {
        id
        apiKey
        handle
        title
        developerName
        embedded
        previouslyInstalled
        requestedAccessScopes {
          handle
          description
        }
      }
      activeSubscriptions {
        id
        name
        status
        test
        trialDays
        currentPeriodEnd
        createdAt
        lineItems {
          id
          plan {
            pricingDetails {
              __typename
              ... on AppRecurringPricing {
                price {
                  amount
                  currencyCode
                }
                interval
                planHandle
              }
              ... on AppUsagePricing {
                cappedAmount {
                  amount
                  currencyCode
                }
                balanceUsed {
                  amount
                  currencyCode
                }
                interval
                terms
              }
            }
          }
        }
      }
      allSubscriptions(first: $first) {
        nodes {
          id
          name
          status
          test
          trialDays
          currentPeriodEnd
          createdAt
        }
        edges {
          cursor
          node {
            id
          }
        }
        pageInfo {
          hasNextPage
          hasPreviousPage
          startCursor
          endCursor
        }
      }
      oneTimePurchases(first: $first) {
        nodes {
          id
          name
          status
          test
          createdAt
          price {
            amount
            currencyCode
          }
        }
        edges {
          cursor
          node {
            id
          }
        }
        pageInfo {
          hasNextPage
          hasPreviousPage
          startCursor
          endCursor
        }
      }
    }
    missingAppInstallation: appInstallation(id: $unknownInstallationId) {
      id
    }
  }

appLookups.query:
#graphql
  query AppLookupShapes(
    $id: ID!
    $missingId: ID!
    $handle: String!
    $missingHandle: String!
    $apiKey: String!
    $missingApiKey: String!
  ) {
    appById: app(id: $id) {
      id
      apiKey
      handle
      title
      developerName
      embedded
      previouslyInstalled
      requestedAccessScopes {
        handle
        description
      }
    }
    missingAppById: app(id: $missingId) {
      id
    }
    appByHandle(handle: $handle) {
      id
      apiKey
      handle
      title
      developerName
      embedded
      previouslyInstalled
    }
    missingAppByHandle: appByHandle(handle: $missingHandle) {
      id
    }
    appByKey(apiKey: $apiKey) {
      id
      apiKey
      handle
      title
      developerName
      embedded
      previouslyInstalled
    }
    missingAppByKey: appByKey(apiKey: $missingApiKey) {
      id
    }
  }

